{
 "level": "B1–B2",
 "intro": "In this topic, you will learn <strong>causative construction</strong> - a way of saying that someone else performs an action for you (usually for money or at your request).",
 "rules": [
 {
 "label": "Have",
 "color": "emerald",
 "text": "<strong>have + object + V3</strong> (more formally):",
 "example": "I had my car repaired."
 },
 {
 "label": "Get",
 "color": "blue",
 "text": "<strong>get + object + V3</strong> (more colloquial):",
 "example": "I got my hair cut."
 },
 {
 "label": "Value",
 "color": "amber",
 "text": "Someone <strong>else</strong> performs an action for you:",
 "example": "I don't cut my hair myself — a hairdresser does it."
 }
 ]
}

{
 "title": "1. Causative vs Active vs Passive",
 "intro": "Comparison of three designs:",
 "rows": [
 {
 "en": "Active: I repaired my car.",
 "ua": "Active: I repaired my car.",
 "note": "I did it myself."
 },
 {
 "en": "Passive: My car was repaired.",
 "ua": "Passive: My car was repaired.",
 "note": "Someone did it (it is not known who)."
 },
 {
 "en": "Causative: I had my car repaired.",
 "ua": "Causative: I had my car repaired.",
 "note": "I ordered a service (someone did it for me)."
 }
 ],
 "warning": "📌 The causative emphasizes that we organized the performance of the action, and did not do it ourselves!"
}

{
 "title": "2. Have something done at different times",
 "intro": "The verb <strong>have</strong> changes by tense:",
 "items": [
 {
 "label": "Present Simple",
 "title": "have/has + object + V3",
 "subtitle": "I have my hair cut every month."
 },
 {
 "label": "Past Simple",
 "title": "had + object + V3",
 "subtitle": "She had her car serviced yesterday."
 },
 {
 "label": "Future Simple",
 "title": "will have + object + V3",
 "subtitle": "I will have my suit cleaned tomorrow."
 },
 {
 "label": "Present Perfect",
 "title": "have/has had + object + V3",
 "subtitle": "We have had our house painted."
 },
 {
 "label": "Present Continuous",
 "title": "am/is/are having + object + V3",
 "subtitle": "They are having their kitchen renovated."
 },
 {
 "label": "Modal verbs",
 "title": "modal + have + object + V3",
 "subtitle": "You should have your eyes tested."
 }
 ]
}

{
 "title": "3. Typical situations for the causative",
 "sections": [
 {
 "label": "Services / service",
 "color": "emerald",
 "description": "When we <strong>order a service</strong>:",
 "examples": [
 {
 "en": "I had my hair cut yesterday.",
 "ua": "I had my hair cut yesterday."
 },
 {
 "en": "She has her nails done every week.",
 "ua": "She has her nails done every week."
 },
 {
 "en": "We had the house painted last month.",
 "ua": "We had the house painted last month."
 }
 ]
 },
 {
 "label": "Repair / maintenance",
 "color": "blue",
 "description": "For <strong>repair and maintenance</strong>:",
 "examples": [
 {
 "en": "I need to have my car serviced.",
 "ua": "I need to have my car serviced."
 },
 {
 "en": "They had their roof repaired.",
 "ua": "They had their roof repaired."
 },
 {
 "en": "You should have your brakes checked.",
 "ua": "You should have your brakes checked."
 }
 ]
 },
 {
 "label": "Medical services",
 "color": "amber",
 "description": "For <strong>medical</strong> procedures:",
 "examples": [
 {
 "en": "I had my eyes tested last week.",
 "ua": "I had my eyes tested last week."
 },
 {
 "en": "She needs to have her teeth cleaned.",
 "ua": "She needs to have her teeth cleaned."
 },
 {
 "en": "He had his blood pressure checked.",
 "ua": "He had his blood pressure checked."
 }
 ]
 },
 {
 "label": "Delivery / installation",
 "color": "rose",
 "description": "For <strong>delivery and installation</strong>:",
 "examples": [
 {
 "en": "We had a new kitchen installed.",
 "ua": "We had a new kitchen installed."
 },
 {
 "en": "They had the furniture delivered.",
 "ua": "They had the furniture delivered."
 },
 {
 "en": "I had the internet connected yesterday.",
 "ua": "I had the internet connected yesterday."
 }
 ]
 }
 ]
}

{
 "title": "4. Have something done vs Get something done",
 "intro": "Both forms have a similar meaning, but there are differences:",
 "rows": [
 {
 "en": "Have: I had my car repaired.",
 "ua": "Have: I had my car repaired.",
 "note": "More formal, neutral."
 },
 {
 "en": "Get: I got my car repaired.",
 "ua": "Get: I got my car repaired.",
 "note": "More conversational, emphasizes effort."
 },
 {
 "en": "Have: She had her dress made.",
 "ua": "Have: She had her dress made.",
 "note": "Standard service."
 },
 {
 "en": "Get: She finally got her dress made.",
 "ua": "Get: She finally got her dress made.",
 "note": "He emphasizes that it was not easy."
 }
 ],
 "warning": "📌 Get often emphasizes that you had to make an effort to get something done!"
}

{
 "title": "5. Negative causative (unpleasant events)",
 "sections": [
 {
 "label": "Negative events",
 "color": "rose",
 "description": "The causative is also used for <strong>unpleasant events</strong> that happened to us:",
 "examples": [
 {
 "en": "I had my wallet stolen.",
 "ua": "I had my wallet stolen."
 },
 {
 "en": "She had her car broken into.",
 "ua": "She had her car broken into."
 },
 {
 "en": "They had their house burgled.",
 "ua": "They had their house burgled."
 }
 ]
 },
 {
 "label": "The difference is in the context",
 "color": "amber",
 "description": "Context determines whether it is a <strong>service</strong> or a <strong>nuisance</strong>:",
 "examples": [
 {
 "en": "I had my hair cut.",
 "ua": "I had my hair cut."
 },
 {
 "en": "I had my bag stolen.",
 "ua": "I had my bag stolen."
 },
 {
 "en": "She had her phone repaired.",
 "ua": "She had her phone repaired."
 }
 ]
 }
 ]
}

{
 "title": "6. Negatives and questions",
 "intro": "Formation of negatives and questions in the causative case:",
 "items": [
 {
 "label": "Negation (have)",
 "title": "don't/doesn't/didn't have + obj + V3",
 "subtitle": "I didn't have my car repaired."
 },
 {
 "label": "denial (get)",
 "title": "don't/doesn't/didn't get + obj + V3",
 "subtitle": "She didn't get her hair done."
 },
 {
 "label": "question (have)",
 "title": "Do/Does/Did + subj + have + obj + V3?",
 "subtitle": "Did you have your car serviced?"
 },
 {
 "label": "question (get)",
 "title": "Do/Does/Did + subj + get + obj + V3?",
 "subtitle": "Did she get her dress made?"
 },
 {
 "label": "Wh question",
 "title": "Wh + do/does/did + subj + have/get + obj + V3?",
 "subtitle": "Where did you have your hair cut?"
 },
 {
 "label": "Future",
 "title": "Will + subj + have/get + obj + V3?",
 "subtitle": "Will you have the report finished?"
 }
 ]
}

{
 "title": "7. Typical mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "Using the infinitive instead of V3.",
 "wrong": "I had my car to repair.",
 "right": "✅ I had my car repaired."
 },
 {
 "label": "Error 2",
 "color": "amber",
 "title": "Passing object between have/get and V3.",
 "wrong": "I had repaired my car.",
 "right": "✅ I had my car repaired."
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Confusion of the causative with the active state.",
 "wrong": "I had cut my hair.",
 "right": "✅ I had my hair cut."
 },
 {
 "label": "Error 4",
 "color": "rose",
 "title": "Incorrect word order.",
 "wrong": "I had repaired my car yesterday.",
 "right": "✅ I had my car repaired yesterday."
 }
 ]
}
